solution: ```class Solution {
    public int findBestValue(int[] arr, int target) {
        Arrays.sort(arr);
        int n = arr.length;
        int[] prefix = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefix[i + 1] = prefix[i] + arr[i];
        }
        int left = 0, right = arr[n - 1];
        int best = 0, minDiff = Integer.MAX_VALUE;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            int sum = 0;
            int idx = Arrays.binarySearch(arr, mid);
            if (idx < 0) idx = -idx - 1;
            sum = prefix[idx] + (n - idx) * mid;
            int diff = Math.abs(sum - target);
            if (diff < minDiff || (diff == minDiff && mid < best)) {
                minDiff = diff;
                best = mid;
            }
            if (sum < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return best;
    }
}
